using System.ComponentModel.Composition;
using XrmToolBox.Extensibility;
using XrmToolBox.Extensibility.Interfaces;

namespace SolutionOperationMonitor
{
    // Hinweis: Version und Autor werden über die csproj-Properties (Version / Company) gesetzt.
    // Base64-Icons können später über https://www.base64-image.de/ erzeugt und hier eingetragen werden.
    [Export(typeof(IXrmToolBoxPlugin)),
        ExportMetadata("Name", "Solution Operation Monitor"),
        ExportMetadata("Description", "Live progress monitoring for solution import / upgrade / uninstall including percentage, ETA, progress chart and the full solution history at a glance."),
        // 32x32 px Icon als Base64
        ExportMetadata("SmallImageBase64", ""),
        // 80x80 px Icon als Base64
        ExportMetadata("BigImageBase64", ""),
        ExportMetadata("BackgroundColor", "#F0F4FF"),
        ExportMetadata("PrimaryFontColor", "#1B2A4A"),
        ExportMetadata("SecondaryFontColor", "#5A6B8C")]
    public class SolutionOperationMonitorPlugin : PluginBase
    {
        public override IXrmToolBoxPluginControl GetControl()
        {
            return new MonitorControl();
        }
    }
}
